SELECT sh.history_seq AS historySeq, sh.stock_seq AS stockSeq, sh.batch_seq AS batchSeq, sh.transaction_type AS transactionType, sh.change_quantity AS changeQuantity, sh.current_total_stock AS currentTotalStock, sh.detail_stock_name AS detailStockName, sh.price, sh.expiration_date AS expirationDate, sh.reason, sh.memo, sh.created_at AS createdAt FROM stock_history sh JOIN stocks s ON sh.stock_seq = s.stock_seq WHERE s.store_seq = ( CASE WHEN #{storeSeq} IS NOT NULL AND #{storeSeq} != 0 THEN #{storeSeq} ELSE (SELECT store_seq FROM stores WHERE user_seq = #{userSeq} ORDER BY store_seq ASC LIMIT 1) END )
AND sh.stock_seq = #{stockSeq}
AND sh.transaction_type = #{transactionType}
AND sh.created_at >= #{startDate}
AND sh.created_at <= CONCAT(#{endDate}, ' 23:59:59')
AND (sh.detail_stock_name LIKE CONCAT('%', #{keyword}, '%') OR sh.reason LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY sh.history_seq DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM stock_history sh
JOIN stocks s ON sh.stock_seq = s.stock_seq
WHERE s.store_seq = (
    CASE WHEN #{storeSeq} IS NOT NULL AND #{storeSeq} != 0 THEN #{storeSeq}
    ELSE (SELECT store_seq FROM stores WHERE user_seq = #{userSeq} ORDER BY store_seq ASC LIMIT 1)
    END
)

